```c
#include <openssl/bio.h>
#include <openssl/ssl.h>
#include <openssl/err.h>
#include <sys/socket.h>

// ...

// The SSL* and socket_fd are assumed to be already set up and connected
SSL* ssl;
int socket_fd;  // The socket file descriptor for the TCP connection

// This buffer will hold the plaintext data that we want to send
const char plaintext[] = "Hello, TLS world!";
// Calculate the length of the plaintext data
int plaintext_len = sizeof(plaintext) - 1;  // -1 to exclude the null terminator

// Attempt to write plaintext data into the SSL object for encryption
int written = SSL_write(ssl, plaintext, plaintext_len);
if (written <= 0) {
    // Handle SSL_write error - This could include SSL_ERROR_WANT_WRITE
} else {
    // Now retrieve the encrypted data from OpenSSL's write BIO
    char encrypted_data[4096];
    // Read the encrypted data from OpenSSL's write BIO
    int encrypted_len = BIO_read(SSL_get_wbio(ssl), encrypted_data, sizeof(encrypted_data));
    if (encrypted_len > 0) {
        // Successfully read 'encrypted_len' bytes of encrypted data into 'encrypted_data'

        // Now send the encrypted data over the socket
        ssize_t sent = send(socket_fd, encrypted_data, encrypted_len, 0);
        if (sent == -1) {
            // Handle send error (socket error)
        } else if (sent < encrypted_len) {
            // Not all data was sent, handle the partial send (e.g., by buffering the rest)
        }
        // Successfully encrypted and sent 'sent' bytes of data
    } else {
        // BIO_read error (or no data was available to read)
    }
}

// ...
```
Remember that the success of `SSL_write()` does not mean the data has actually been sent over the network; it only means that OpenSSL has successfully processed it. You'll need to manage sending the encrypted data yourself, as demonstrated with the `send()` function call in the example.

Also, be cautious when handling partial writes and consider implementing a buffer management strategy to handle cases where `send()` is unable to send all the encrypted data in one go, especially if you're working with a non-blocking socket.
